"use client";
import { useEffect, useState, useRef } from "react";
import { usePathname } from "next/navigation";

import { ReactLenis } from "lenis/react";
import { registerScrollTrigger, ScrollTrigger } from "@/ui/animations/scrollTrigger";
import Preloader from "@/components/Preloader/Preloader";
import AffiliateCapture from "@/components/AffiliateCapture/AffiliateCapture";
import ReferralCapture from "@/components/ReferralCapture/ReferralCapture";

// Clearance for the fixed header (.menu) so an anchored section doesn't land
// underneath it.
const ANCHOR_SCROLL_OFFSET = 100;

export default function ClientLayout({ children, footer, header }) {
  const pageRef = useRef();
  const lenisRef = useRef(null);
  const pathname = usePathname();

  const [isMobile, setIsMobile] = useState(false);

  // Kill the mobile "jitter" caused by the browser's URL/tab bar showing and
  // hiding as you scroll: that fires a resize (height-only) which makes
  // ScrollTrigger recompute every pin/start and snap the layout. `ignoreMobileResize`
  // tells ScrollTrigger to ignore those toolbar-driven height changes. Set once,
  // globally — applies to every ScrollTrigger on every page. (We deliberately do
  // NOT use normalizeScroll, which would conflict with Lenis.)
  useEffect(() => {
    registerScrollTrigger();
    ScrollTrigger.config({ ignoreMobileResize: true });
  }, []);

  // Freeze a stable viewport height in CSS (--app-height). Full-height heroes
  // use this instead of 100svh/100vh so they DON'T resize when Chrome/Safari
  // mobile slide their top/bottom bars in and out on scroll (which only changes
  // the height and was making the hero — and the whole page — jump). We lock the
  // pixel height at load and only recompute it on a real WIDTH change (rotation
  // or desktop window resize), never on the toolbar's height-only resizes.
  useEffect(() => {
    const root = document.documentElement;
    const setAppHeight = () => {
      root.style.setProperty("--app-height", `${window.innerHeight}px`);
    };
    setAppHeight();
    let lastWidth = window.innerWidth;
    const onResize = () => {
      if (window.innerWidth !== lastWidth) {
        lastWidth = window.innerWidth;
        setAppHeight();
      }
    };
    window.addEventListener("resize", onResize);
    window.addEventListener("orientationchange", setAppHeight);
    return () => {
      window.removeEventListener("resize", onResize);
      window.removeEventListener("orientationchange", setAppHeight);
    };
  }, []);

  // Cart buttons on product cards "open" (slide out the "Add to cart" label) on
  // tap. Touch :hover/:focus/:active are unreliable (flicker / open only while
  // held / icon shake), so we drive the open state with a stable class instead:
  // tapping a cart button adds `.cart-open` (and closes any other open one).
  useEffect(() => {
    const onClick = (e) => {
      const btn = e.target.closest?.(".product-card-cart-btn");
      document
        .querySelectorAll(".product-card-cart-btn.cart-open")
        .forEach((b) => {
          if (b !== btn) b.classList.remove("cart-open");
        });
      if (btn) btn.classList.add("cart-open");
    };
    document.addEventListener("click", onClick);
    return () => document.removeEventListener("click", onClick);
  }, []);

  useEffect(() => {
    const checkMobile = () => {
      // Only treat WIDTH crossing the breakpoint as a real change; ignore the
      // height-only resizes from the mobile toolbar so we don't thrash state.
      setIsMobile(window.innerWidth <= 1000);
    };

    checkMobile();
    window.addEventListener("resize", checkMobile);
    return () => window.removeEventListener("resize", checkMobile);
  }, []);

  // On every route change, jump to the top (hero) — unless the URL carries a
  // hash (e.g. /touchpoint#faq), in which case land on that section instead.
  // Lenis owns the scroll position via rAF, so a bare window.scrollTo (and the
  // browser's own anchor jump) gets reverted on the next tick — drive Lenis's
  // own scrollTo (immediate) either way. Falls back to native if Lenis isn't
  // ready yet.
  useEffect(() => {
    const lenis = lenisRef.current?.lenis;

    const jumpToTop = () => {
      if (lenis) lenis.scrollTo(0, { immediate: true, force: true });
      else window.scrollTo(0, 0);
    };

    const scrollToEl = (el) => {
      if (lenis) {
        lenis.scrollTo(el, {
          offset: -ANCHOR_SCROLL_OFFSET,
          immediate: true,
          force: true,
        });
      } else {
        el.scrollIntoView();
      }
    };

    const id = window.location.hash.slice(1);
    const target = id && document.getElementById(id);
    if (target) {
      scrollToEl(target);
      return;
    }

    // No target (yet): start at the top, as every route change always has.
    jumpToTop();
    if (!id) return;

    // The section may still be mounting — these pages are client-rendered and
    // some wait on async data. Watch and go once it appears. We never jump back
    // to top from here: pages with their own hash handling (e.g. /ritual#evening)
    // own the scroll position once we've defaulted to top.
    //
    // Deadline is TIME-based, not a frame count. The old 90-frame budget assumed
    // 60fps (~1.5s), but it burns down at whatever rate the page actually
    // renders — and on a data-fetching page like /unit/[slug] (which also
    // arrives via a redirect from /unit, restarting the watch) the section
    // mounts after the product request resolves, so the budget ran out before
    // the anchor ever existed and the deep link silently landed on the hero.
    const deadline = Date.now() + 8000;
    let cancelled = false;
    // If the reader starts scrolling while we wait, the page is theirs — never
    // yank them to the anchor after the fact.
    const onUserScroll = () => { cancelled = true; };
    window.addEventListener("wheel", onUserScroll, { passive: true, once: true });
    window.addEventListener("touchstart", onUserScroll, { passive: true, once: true });

    // Finding the element is NOT enough to scroll to it. Lenis caches the page
    // dimensions and clamps any target to that cached limit — so on a page that
    // just mounted (or whose images haven't loaded) the limit is still tiny, the
    // target clamps to ~0, and scrollTo silently no-ops. Hence: resize() first
    // to refresh the limit, then re-assert every frame while late content keeps
    // shifting the anchor, and stop once it actually settles at the offset.
    let settledFrames = 0;
    let raf = requestAnimationFrame(function waitForTarget() {
      if (cancelled) return;
      const el = document.getElementById(id);
      if (el) {
        lenis?.resize();
        const delta = el.getBoundingClientRect().top - ANCHOR_SCROLL_OFFSET;
        if (Math.abs(delta) > 2) {
          scrollToEl(el);
          settledFrames = 0;
        } else if (++settledFrames > 8) {
          return; // parked on the anchor for 8 straight frames — done
        }
      }
      if (Date.now() < deadline) raf = requestAnimationFrame(waitForTarget);
    });

    return () => {
      cancelAnimationFrame(raf);
      window.removeEventListener("wheel", onUserScroll);
      window.removeEventListener("touchstart", onUserScroll);
    };
  }, [pathname]);

  // Same-page anchor clicks (already on /touchpoint, clicking FAQ in the footer)
  // never change `pathname`, so the effect above won't fire — and Lenis would
  // fight the browser's native jump. Drive those through Lenis too.
  useEffect(() => {
    const onHashChange = () => {
      const el = document.getElementById(window.location.hash.slice(1));
      if (!el) return;
      const lenis = lenisRef.current?.lenis;
      if (lenis) lenis.scrollTo(el, { offset: -ANCHOR_SCROLL_OFFSET });
      else el.scrollIntoView({ behavior: "smooth" });
    };
    window.addEventListener("hashchange", onHashChange);
    return () => window.removeEventListener("hashchange", onHashChange);
  }, []);

  const scrollSettings = isMobile
    ? {
        duration: 0.45,
        easing: (t) => Math.min(1, 1.001 - Math.pow(2, -10 * t)),
        direction: "vertical",
        gestureDirection: "vertical",
        smooth: true,
        smoothTouch: false,
        touchMultiplier: 1,
        infinite: false,
        lerp: 0.12,
        wheelMultiplier: 1,
        orientation: "vertical",
        smoothWheel: false,
        syncTouch: false,
      }
    : {
        // Lerp ONLY — deliberately no `duration`/`easing` here. Lenis treats the
        // two as mutually exclusive and duration wins (see Animate.advance), and
        // a duration-based tween restarts from currentTime=0 on EVERY wheel
        // event. With an expo-out easing that means each tick lurches fast then
        // decelerates, and a continuous wheel/trackpad gesture reads as judder.
        // `lerp` uses frame-rate-independent damping toward a moving target, so
        // overlapping wheel events blend smoothly instead of restarting.
        direction: "vertical",
        gestureDirection: "vertical",
        smooth: true,
        smoothTouch: false,
        touchMultiplier: 2,
        infinite: false,
        lerp: 0.1,
        wheelMultiplier: 1,
        orientation: "vertical",
        smoothWheel: true,
        syncTouch: false,
      };

  return (
    <ReactLenis root options={scrollSettings} ref={lenisRef}>
      <AffiliateCapture />
      <ReferralCapture />
      <Preloader />
      <div className="page" ref={pageRef}>
        {pathname !== "/login" && header}
        {children}
        {pathname !== "/lookbook" && pathname !== "/login" && footer}
      </div>
    </ReactLenis>
  );
}
